create table usuario (id bigint not null, data_cadastro datetime not null, email varchar(255) not null, nome varchar(255) not null, senha varchar(255) not null, primary key (id)) engine=MyISAM;
create table usuario_grupos (usuario_id bigint not null, grupos_id bigint not null) engine=MyISAM;
